import { Logger } from '../utils/logger';

interface CacheEntry<T> {
  value: T;
  timestamp: number;
  ttl: number;
}

interface CacheOptions {
  defaultTtl: number;
  maxSize: number;
  onEvict?: (key: string, value: unknown) => void;
}

export class RequestCache<T = unknown> {
  private readonly cache: WeakMap<object, CacheEntry<T>>;
  private readonly logger: Logger;
  private readonly options: CacheOptions;
  private hits = 0;
  private misses = 0;

  constructor(options: Partial<CacheOptions> = {}) {
    this.cache = new WeakMap();
    this.logger = new Logger('RequestCache');
    this.options = {
      defaultTtl: 60000,
      maxSize: 1000,
      ...options,
    };
  }

  get(key: string): T | undefined {
    const entry = this.cache.get(key as unknown as object);
    if (!entry) {
      this.misses++;
      return undefined;
    }

    if (Date.now() - entry.timestamp > entry.ttl) {
      this.cache.delete(key as unknown as object);
      this.misses++;
      return undefined;
    }

    this.hits++;
    return entry.value;
  }

  set(key: string, value: T, ttl?: number): void {
    const entry: CacheEntry<T> = {
      value,
      timestamp: Date.now(),
      ttl: ttl ?? this.options.defaultTtl,
    };
    this.cache.set(key as unknown as object, entry);
    this.logger.debug(`Cached key: ${key}`);
  }

  delete(key: string): boolean {
    return this.cache.delete(key as unknown as object);
  }

  getStats() {
    const total = this.hits + this.misses;
    return {
      hits: this.hits,
      misses: this.misses,
      hitRate: total > 0 ? this.hits / total : 0,
    };
  }

  clear(): void {
    this.cache = new WeakMap();
    this.hits = 0;
    this.misses = 0;
  }
}

export function createRequestCache<T>(options?: Partial<CacheOptions>) {
  return new RequestCache<T>(options);
}

