export interface TruncateOptions {
  maxLength: number;
  ellipsis?: string;
  wordBoundary?: boolean;
  preserveWords?: boolean;
}

const DEFAULT_ELLIPSIS = '...';

export function getCharacterCount(text: string): number {
  return text.length;
}

export function truncateText(
  text: string,
  options: TruncateOptions
): string {
  const {
    maxLength,
    ellipsis = DEFAULT_ELLIPSIS,
    wordBoundary = false,
  } = options;

  if (text.length <= maxLength) {
    return text;
  }

  const truncateAt = maxLength - ellipsis.length;

  if (truncateAt <= 0) {
    return ellipsis.slice(0, maxLength);
  }

  let truncated = text.slice(0, truncateAt);

  if (wordBoundary) {
    const lastSpace = truncated.lastIndexOf(' ');
    if (lastSpace > truncateAt * 0.5) {
      truncated = truncated.slice(0, lastSpace);
    }
  }

  return truncated + ellipsis;
}

export function truncateMiddle(
  text: string,
  maxLength: number,
  separator: string = '...'
): string {
  if (text.length <= maxLength) {
    return text;
  }

  const separatorLength = separator.length;
  const charsToShow = maxLength - separatorLength;

  if (charsToShow <= 0) {
    return separator.slice(0, maxLength);
  }

  const frontChars = Math.ceil(charsToShow / 2);
  const backChars = Math.floor(charsToShow / 2);

  return text.slice(0, frontChars) + separator + text.slice(-backChars);
}

export function countWords(text: string): number {
  return text.trim().split(/\s+/).filter(Boolean).length;
}

export function truncateWords(
  text: string,
  maxWords: number,
  ellipsis: string = DEFAULT_ELLIPSIS
): string {
  const words = text.trim().split(/\s+/);

  if (words.length <= maxWords) {
    return text;
  }

  return words.slice(0, maxWords).join(' ') + ellipsis;
}

export class TextTruncator {
  private defaultOptions: TruncateOptions;

  constructor(defaultOptions: Partial<TruncateOptions> = {}) {
    this.defaultOptions = {
      maxLength: 100,
      ellipsis: DEFAULT_ELLIPSIS,
      wordBoundary: true,
      ...defaultOptions,
    };
  }

  truncate(text: string, options?: Partial<TruncateOptions>): string {
    return truncateText(text, { ...this.defaultOptions, ...options });
  }

  truncateForDisplay(text: string, maxLength: number): string {
    return truncateText(text, {
      ...this.defaultOptions,
      maxLength,
      wordBoundary: true,
    });
  }

  getLength(text: string): number {
    return getCharacterCount(text);
  }

  isWithinLimit(text: string, limit: number): boolean {
    return this.getLength(text) <= limit;
  }
}

export default TextTruncator;
```

