export type MessageHandler = (data: unknown) => void;
export type ConnectionHandler = () => void;
export type ErrorHandler = (error: Event) => void;

export interface WebSocketConfig {
  url: string;
  protocols?: string[];
  reconnectInterval: number;
  maxReconnectAttempts: number;
  heartbeatInterval: number;
  messageQueueSize: number;
}

export interface QueuedMessage {
  data: string;
  timestamp: number;
  priority: number;
}

const DEFAULT_CONFIG: Partial<WebSocketConfig> = {
  reconnectInterval: 1000,
  maxReconnectAttempts: 10,
  heartbeatInterval: 30000,
  messageQueueSize: 100,
};

export class WebSocketManager {
  private socket: WebSocket | null = null;
  private config: WebSocketConfig;
  private messageHandlers: Map<string, Set<MessageHandler>> = new Map();
  private connectionHandlers: Set<ConnectionHandler> = new Set();
  private errorHandlers: Set<ErrorHandler> = new Set();
  private messageQueue: QueuedMessage[] = [];
  private reconnectAttempts = 0;
  private reconnectTimeout: NodeJS.Timeout | null = null;
  private heartbeatInterval: NodeJS.Timeout | null = null;
  private isConnecting = false;
  private isIntentionallyClosed = false;

  constructor(config: Partial<WebSocketConfig> & { url: string }) {
    this.config = { ...DEFAULT_CONFIG, ...config } as WebSocketConfig;
  }

  connect(): void {
    if (this.socket?.readyState === WebSocket.OPEN || this.isConnecting) {
      return;
    }

    this.isConnecting = true;
    this.isIntentionallyClosed = false;

    try {
      this.socket = new WebSocket(this.config.url, this.config.protocols);
      this.setupEventHandlers();
    } catch (error) {
      this.isConnecting = false;
      this.handleReconnect();
    }
  }

  private setupEventHandlers(): void {
    if (!this.socket) return;

    this.socket.onopen = () => {
      this.isConnecting = false;
      this.reconnectAttempts = 0;
      this.startHeartbeat();
      this.flushMessageQueue();
      this.connectionHandlers.forEach(handler => handler());
    };

    this.socket.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data);
        const type = message.type || 'default';
        const handlers = this.messageHandlers.get(type);

        if (handlers) {
          handlers.forEach(handler => handler(message.payload));
        }
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error);
      }
    };

    this.socket.onclose = (event) => {
      this.stopHeartbeat();
      this.isConnecting = false;

      if (!this.isIntentionallyClosed && !event.wasClean) {
        this.handleReconnect();
      }
    };

    this.socket.onerror = (error) => {
      this.errorHandlers.forEach(handler => handler(error));
    };
  }

  private handleReconnect(): void {
    if (this.reconnectAttempts >= this.config.maxReconnectAttempts) {
      console.error('Max reconnection attempts reached');
      return;
    }

    const delay = this.config.reconnectInterval * Math.pow(2, this.reconnectAttempts);
    this.reconnectAttempts++;

    this.reconnectTimeout = setTimeout(() => {
      this.connect();
    }, delay);
  }

  private startHeartbeat(): void {
    this.heartbeatInterval = setInterval(() => {
      if (this.socket?.readyState === WebSocket.OPEN) {
        this.socket.send(JSON.stringify({ type: 'ping' }));
      }
    }, this.config.heartbeatInterval);
  }

  private stopHeartbeat(): void {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }
  }

  private flushMessageQueue(): void {
    while (this.messageQueue.length > 0 && this.socket?.readyState === WebSocket.OPEN) {
      const message = this.messageQueue.shift();
      if (message) {
        this.socket.send(message.data);
      }
    }
  }

  send(type: string, payload: unknown, priority = 0): boolean {
    const message = JSON.stringify({ type, payload });

    if (this.socket?.readyState === WebSocket.OPEN) {
      this.socket.send(message);
      return true;
    }

    if (this.messageQueue.length < this.config.messageQueueSize) {
      this.messageQueue.push({
        data: message,
        timestamp: Date.now(),
        priority,
      });
      this.messageQueue.sort((a, b) => b.priority - a.priority);
      return true;
    }

    return false;
  }

  on(type: string, handler: MessageHandler): () => void {
    if (!this.messageHandlers.has(type)) {
      this.messageHandlers.set(type, new Set());
    }
    this.messageHandlers.get(type)!.add(handler);

    return () => {
      this.messageHandlers.get(type)?.delete(handler);
    };
  }

  onConnect(handler: ConnectionHandler): () => void {
    this.connectionHandlers.add(handler);
    return () => this.connectionHandlers.delete(handler);
  }

  onError(handler: ErrorHandler): () => void {
    this.errorHandlers.add(handler);
    return () => this.errorHandlers.delete(handler);
  }

  disconnect(): void {
    this.isIntentionallyClosed = true;

    if (this.reconnectTimeout) {
      clearTimeout(this.reconnectTimeout);
    }

    this.stopHeartbeat();

    if (this.socket) {
      this.socket.close();
      this.socket = null;
    }
  }

  getReadyState(): number {
    return this.socket?.readyState ?? WebSocket.CLOSED;
  }

  isConnected(): boolean {
    return this.socket?.readyState === WebSocket.OPEN;
  }
}

export function createWebSocketManager(
  config: Partial<WebSocketConfig> & { url: string }
): WebSocketManager {
  return new WebSocketManager(config);
}
```

