import subprocess
import os
from pathlib import Path
from dataclasses import dataclass
from typing import Optional
import logging

logger = logging.getLogger(__name__)


@dataclass
class GitResult:
    success: bool
    output: str
    error: str | None = None


class GitHelper:
    def __init__(self, repo_path: str):
        self.repo_path = Path(repo_path)
        if not (self.repo_path / ".git").exists():
            raise ValueError(f"Not a git repository: {repo_path}")

    def run_command(self, command: str) -> GitResult:
        try:
            result = subprocess.run(
                command,
                shell=True,
                cwd=self.repo_path,
                capture_output=True,
                text=True
            )
            return GitResult(
                success=result.returncode == 0,
                output=result.stdout.strip(),
                error=result.stderr.strip() if result.stderr else None
            )
        except Exception as e:
            return GitResult(success=False, output="", error=str(e))

    def get_current_branch(self) -> str:
        result = self.run_command("git branch --show-current")
        return result.output if result.success else "unknown"

    def checkout(self, branch: str) -> GitResult:
        return self.run_command(f"git checkout {branch}")

    def create_branch(self, branch_name: str) -> GitResult:
        return self.run_command(f"git checkout -b {branch_name}")

    def commit(self, message: str) -> GitResult:
        return self.run_command(f'git commit -m "{message}"')

    def get_log(self, count: int = 10, author: str = None) -> GitResult:
        cmd = f"git log -n {count}"
        if author:
            cmd += f' --author="{author}"'
        return self.run_command(cmd)

    def diff(self, file_path: str = None) -> GitResult:
        cmd = "git diff"
        if file_path:
            cmd += f" -- {file_path}"
        return self.run_command(cmd)

    def add_files(self, *files: str) -> GitResult:
        files_str = " ".join(files)
        return self.run_command(f"git add {files_str}")

    def get_status(self) -> GitResult:
        return self.run_command("git status --porcelain")


def clone_repository(url: str, destination: str) -> GitResult:
    try:
        result = subprocess.run(
            f"git clone {url} {destination}",
            shell=True,
            capture_output=True,
            text=True
        )
        return GitResult(
            success=result.returncode == 0,
            output=result.stdout.strip(),
            error=result.stderr.strip() if result.stderr else None
        )
    except Exception as e:
        return GitResult(success=False, output="", error=str(e))

