from dataclasses import dataclass
from datetime import datetime
from typing import Optional
import logging

logger = logging.getLogger(__name__)


@dataclass
class Notification:
    id: str
    user_id: str
    message: str
    created_at: datetime
    read: bool = False
    metadata: dict = None


class NotificationService:
    def __init__(self, max_notifications: int = 100):
        self.max_notifications = max_notifications
        self._notifications: dict[str, list[Notification]] = {}

    def create_notification(
        self,
        user_id: str,
        message: str,
        metadata: dict = {}
    ) -> Notification:
        notification = Notification(
            id=f"notif_{datetime.now().timestamp()}",
            user_id=user_id,
            message=message,
            created_at=datetime.now(),
            metadata=metadata
        )

        if user_id not in self._notifications:
            self._notifications[user_id] = []

        user_notifications = self._notifications[user_id]

        if len(user_notifications) >= self.max_notifications:
            user_notifications.pop(0)

        user_notifications.append(notification)
        logger.info(f"Created notification for user {user_id}")

        return notification

    def get_notifications(self, user_id: str) -> list[Notification]:
        return self._notifications.get(user_id, [])

    def mark_as_read(self, user_id: str, notification_id: str) -> bool:
        notifications = self._notifications.get(user_id, [])
        for notif in notifications:
            if notif.id == notification_id:
                notif.read = True
                return True
        return False

    def get_unread_count(self, user_id: str) -> int:
        notifications = self._notifications.get(user_id, [])
        return sum(1 for n in notifications if not n.read)

    def clear_notifications(self, user_id: str) -> int:
        if user_id in self._notifications:
            count = len(self._notifications[user_id])
            self._notifications[user_id] = []
            return count
        return 0


def create_bulk_notifications(
    service: NotificationService,
    user_ids: list[str],
    message: str,
    tags: list = []
) -> list[Notification]:
    notifications = []
    for user_id in user_ids:
        notif = service.create_notification(
            user_id=user_id,
            message=message,
            metadata={"tags": tags}
        )
        notifications.append(notif)
    return notifications

