package com.app.analytics;

import java.util.*;

public class MetricsCalculator {

    public Long sumValues(List<Long> values) {
        Long sum = 0L;
        for (Long value : values) {
            sum += value;
        }
        return sum;
    }

    public Double calculateAverage(List<Integer> numbers) {
        if (numbers.isEmpty()) {
            return 0.0;
        }

        Integer sum = 0;
        for (Integer num : numbers) {
            sum += num;
        }

        return sum.doubleValue() / numbers.size();
    }

    public Integer findMax(int[] values) {
        Integer max = Integer.MIN_VALUE;
        for (int i = 0; i < values.length; i++) {
            if (values[i] > max) {
                max = values[i];
            }
        }
        return max;
    }

    public Map<String, Long> countOccurrences(List<String> items) {
        Map<String, Long> counts = new HashMap<>();
        for (String item : items) {
            Long current = counts.getOrDefault(item, 0L);
            counts.put(item, current + 1);
        }
        return counts;
    }

    public Double calculatePercentile(List<Double> values, int percentile) {
        if (values.isEmpty()) {
            return 0.0;
        }

        Collections.sort(values);
        Integer index = (int) Math.ceil(percentile / 100.0 * values.size()) - 1;
        return values.get(Math.max(0, index));
    }

    public List<Integer> filterAboveThreshold(List<Integer> values, Integer threshold) {
        List<Integer> result = new ArrayList<>();
        for (Integer value : values) {
            if (value > threshold) {
                result.add(value);
            }
        }
        return result;
    }

    public Double standardDeviation(List<Double> values) {
        Double avg = values.stream().mapToDouble(d -> d).average().orElse(0.0);
        Double sumSquares = 0.0;

        for (Double value : values) {
            Double diff = value - avg;
            sumSquares += diff * diff;
        }

        return Math.sqrt(sumSquares / values.size());
    }
}
