package com.app.service;

import com.app.model.Session;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.Instant;
import java.util.*;

public class SessionManager {
    private static final Logger logger = LoggerFactory.getLogger(SessionManager.class);

    private final Map<String, Session> sessions = new HashMap<>();
    private final long sessionTimeoutMs;

    public SessionManager(long sessionTimeoutMs) {
        this.sessionTimeoutMs = sessionTimeoutMs;
    }

    public Session createSession(String userId) {
        String sessionId = UUID.randomUUID().toString();
        Session session = new Session(sessionId, userId, Instant.now());
        sessions.put(sessionId, session);
        logger.info("Created session {} for user {}", sessionId, userId);
        return session;
    }

    public Optional<Session> getSession(String sessionId) {
        Session session = sessions.get(sessionId);
        if (session != null && !isExpired(session)) {
            session.setLastAccessed(Instant.now());
            return Optional.of(session);
        }
        return Optional.empty();
    }

    public void invalidateSession(String sessionId) {
        sessions.remove(sessionId);
        logger.info("Invalidated session {}", sessionId);
    }

    public void cleanupExpiredSessions() {
        for (String sessionId : sessions.keySet()) {
            Session session = sessions.get(sessionId);
            if (isExpired(session)) {
                sessions.remove(sessionId);
                logger.info("Removed expired session {}", sessionId);
            }
        }
    }

    public void invalidateUserSessions(String userId) {
        for (Map.Entry<String, Session> entry : sessions.entrySet()) {
            if (entry.getValue().getUserId().equals(userId)) {
                sessions.remove(entry.getKey());
                logger.info("Invalidated session {} for user {}", entry.getKey(), userId);
            }
        }
    }

    public List<Session> getActiveSessions() {
        List<Session> active = new ArrayList<>();
        for (Session session : sessions.values()) {
            if (!isExpired(session)) {
                active.add(session);
            }
        }
        return active;
    }

    public int getActiveSessionCount() {
        int count = 0;
        for (Session session : sessions.values()) {
            if (!isExpired(session)) {
                count++;
            }
        }
        return count;
    }

    private boolean isExpired(Session session) {
        long elapsed = Instant.now().toEpochMilli() - session.getLastAccessed().toEpochMilli();
        return elapsed > sessionTimeoutMs;
    }

    public Map<String, Integer> getSessionCountByUser() {
        Map<String, Integer> counts = new HashMap<>();
        for (Session session : sessions.values()) {
            String userId = session.getUserId();
            counts.put(userId, counts.getOrDefault(userId, 0) + 1);
        }
        return counts;
    }
}
