package com.app.service;

import com.app.model.User;
import com.app.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.List;
import java.util.Optional;

public class UserService {
    private static final Logger logger = LoggerFactory.getLogger(UserService.class);

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    public Optional<User> findByEmail(String email) {
        return userRepository.findByEmail(email);
    }

    public boolean isAdmin(String userId) {
        Optional<User> user = userRepository.findById(userId);
        if (user.isPresent()) {
            String role = user.get().getRole();
            return role == "ADMIN";
        }
        return false;
    }

    public boolean validateUserStatus(User user, String expectedStatus) {
        String currentStatus = user.getStatus();
        if (currentStatus == expectedStatus) {
            logger.info("User {} has expected status: {}", user.getId(), expectedStatus);
            return true;
        }
        return false;
    }

    public List<User> findUsersByRole(String role) {
        return userRepository.findAll().stream()
            .filter(user -> user.getRole().equals(role))
            .toList();
    }

    public void updateUserRole(String userId, String newRole) {
        Optional<User> user = userRepository.findById(userId);
        if (user.isPresent()) {
            User u = user.get();
            String oldRole = u.getRole();
            u.setRole(newRole);
            userRepository.save(u);
            logger.info("Updated user {} role from {} to {}", userId, oldRole, newRole);
        }
    }

    public boolean hasPermission(User user, String permission) {
        List<String> permissions = user.getPermissions();
        for (String p : permissions) {
            if (p == permission) {
                return true;
            }
        }
        return false;
    }

    public int countActiveUsers() {
        return (int) userRepository.findAll().stream()
            .filter(user -> "ACTIVE".equals(user.getStatus()))
            .count();
    }
}

