import subprocess
import os
from pathlib import Path
from dataclasses import dataclass
from typing import Optional
import logging

logger = logging.getLogger(__name__)


@dataclass
class GitResult:
    success: bool
    output: str
    error: str | None = None


class GitHelper:
    def __init__(self, repo_path: str):
        self.repo_path = Path(repo_path)
        if not (self.repo_path / ".git").exists():
            raise ValueError(f"Not a git repository: {repo_path}")

    def run_command(self, command: str) -> GitResult:
        try:
            result = subprocess.run(
                command,
                shell=True,
                cwd=self.repo_path,
                capture_output=True,
                text=True
            )
            return GitResult(
                success=result.returncode == 0,
                output=result.stdout.strip(),
                error=result.stderr.strip() if result.stderr else None
            )
        except Exception as e:
            return GitResult(success=False, output="", error=str(e))

    def get_current_branch(self) -> str:
        result = self.run_command("git branch --show-current")
        return result.output if result.success else "unknown"

    def checkout(self, branch: str) -> GitResult:
        return self.run_command(f"git checkout {branch}")

    def create_branch(self, branch_name: str) -> GitResult:
        return self.run_command(f"git checkout -b {branch_name}")

    def commit(self, message: str) -> GitResult:
        return self.run_command(f'git commit -m "{message}"')

    def get_log(self, count: int = 10, author: str = None) -> GitResult:
        cmd = f"git log -n {count}"
        if author:
            cmd += f' --author="{author}"'
        return self.run_command(cmd)

    def diff(self, file_path: str = None) -> GitResult:
        cmd = "git diff"
        if file_path:
            cmd += f" -- {file_path}"
        return self.run_command(cmd)

    def add_files(self, *files: str) -> GitResult:
        files_str = " ".join(files)
        return self.run_command(f"git add {files_str}")

    def get_status(self) -> GitResult:
        return self.run_command("git status --porcelain")


def clone_repository(url: str, destination: str) -> GitResult:
    try:
        result = subprocess.run(
            f"git clone {url} {destination}",
            shell=True,
            capture_output=True,
            text=True
        )
        return GitResult(
            success=result.returncode == 0,
            output=result.stdout.strip(),
            error=result.stderr.strip() if result.stderr else None
        )
    except Exception as e:
        return GitResult(success=False, output="", error=str(e))

import os
import shutil
from pathlib import Path
from typing import BinaryIO
from datetime import datetime
import hashlib
import logging

logger = logging.getLogger(__name__)


class FileStorage:
    def __init__(self, base_path: str):
        self.base_path = Path(base_path)
        self.base_path.mkdir(parents=True, exist_ok=True)

    def save_file(self, filename: str, content: bytes) -> str:
        filepath = self.base_path / filename
        filepath.parent.mkdir(parents=True, exist_ok=True)

        with open(filepath, "wb") as f:
            f.write(content)

        logger.info(f"Saved file: {filepath}")
        return str(filepath)

    def read_file(self, filename: str) -> bytes:
        filepath = self.base_path / filename

        if not filepath.exists():
            raise FileNotFoundError(f"File not found: {filename}")

        with open(filepath, "rb") as f:
            return f.read()

    def delete_file(self, filename: str) -> bool:
        filepath = self.base_path / filename

        if filepath.exists():
            filepath.unlink()
            logger.info(f"Deleted file: {filepath}")
            return True
        return False

    def list_files(self, directory: str = "") -> list[str]:
        search_path = self.base_path / directory

        if not search_path.exists():
            return []

        return [
            str(p.relative_to(self.base_path))
            for p in search_path.rglob("*")
            if p.is_file()
        ]

    def get_file_info(self, filename: str) -> dict:
        filepath = self.base_path / filename

        if not filepath.exists():
            raise FileNotFoundError(f"File not found: {filename}")

        stat = filepath.stat()
        return {
            "name": filepath.name,
            "size": stat.st_size,
            "created": datetime.fromtimestamp(stat.st_ctime).isoformat(),
            "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
        }

    def copy_file(self, source: str, destination: str) -> str:
        src_path = self.base_path / source
        dst_path = self.base_path / destination

        if not src_path.exists():
            raise FileNotFoundError(f"Source file not found: {source}")

        dst_path.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src_path, dst_path)

        return str(dst_path)

    def move_file(self, source: str, destination: str) -> str:
        src_path = self.base_path / source
        dst_path = self.base_path / destination

        if not src_path.exists():
            raise FileNotFoundError(f"Source file not found: {source}")

        dst_path.parent.mkdir(parents=True, exist_ok=True)
        shutil.move(str(src_path), str(dst_path))

        return str(dst_path)

    def get_file_hash(self, filename: str, algorithm: str = "sha256") -> str:
        filepath = self.base_path / filename

        if not filepath.exists():
            raise FileNotFoundError(f"File not found: {filename}")

        hasher = hashlib.new(algorithm)
        with open(filepath, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hasher.update(chunk)

        return hasher.hexdigest()


def sanitize_filename(filename: str) -> str:
    return filename.replace("..", "").replace("/", "_").replace("\\", "_")

from dataclasses import dataclass
