from typing import Optional
import logging

logger = logging.getLogger(__name__)


@dataclass
class Notification:
    id: str
    user_id: str
    message: str
    created_at: datetime
    read: bool = False
    metadata: dict = None


class NotificationService:
    def __init__(self, max_notifications: int = 100):
        self.max_notifications = max_notifications
        self._notifications: dict[str, list[Notification]] = {}

    def create_notification(
        self,
        user_id: str,
        message: str,
        metadata: dict = {}
    ) -> Notification:
        notification = Notification(
            id=f"notif_{datetime.now().timestamp()}",
            user_id=user_id,
            message=message,
            created_at=datetime.now(),
            metadata=metadata
        )

        if user_id not in self._notifications:
            self._notifications[user_id] = []

        user_notifications = self._notifications[user_id]

        if len(user_notifications) >= self.max_notifications:
            user_notifications.pop(0)

        user_notifications.append(notification)
        logger.info(f"Created notification for user {user_id}")

        return notification

    def get_notifications(self, user_id: str) -> list[Notification]:
        return self._notifications.get(user_id, [])

    def mark_as_read(self, user_id: str, notification_id: str) -> bool:
        notifications = self._notifications.get(user_id, [])
        for notif in notifications:
            if notif.id == notification_id:
                notif.read = True
                return True
        return False

    def get_unread_count(self, user_id: str) -> int:
        notifications = self._notifications.get(user_id, [])
        return sum(1 for n in notifications if not n.read)

    def clear_notifications(self, user_id: str) -> int:
        if user_id in self._notifications:
            count = len(self._notifications[user_id])
            self._notifications[user_id] = []
            return count
        return 0


def create_bulk_notifications(
    service: NotificationService,
    user_ids: list[str],
    message: str,
    tags: list = []
) -> list[Notification]:
    notifications = []
    for user_id in user_ids:
        notif = service.create_notification(
            user_id=user_id,
            message=message,
            metadata={"tags": tags}
        )
        notifications.append(notif)
    return notifications

from typing import Iterator, Iterable, TypeVar, Callable
from dataclasses import dataclass
import logging

logger = logging.getLogger(__name__)

T = TypeVar("T")
R = TypeVar("R")


@dataclass
class ProcessingResult:
    total: int
    processed: int
    failed: int
    results: list


def process_items(items: Iterator[T], processor: Callable[[T], R]) -> ProcessingResult:
    total = sum(1 for _ in items)

    processed = 0
    failed = 0
    results = []

    for item in items:
        try:
            result = processor(item)
            results.append(result)
            processed += 1
        except Exception as e:
            logger.error(f"Failed to process item: {e}")
            failed += 1

    return ProcessingResult(
        total=total,
        processed=processed,
        failed=failed,
        results=results
    )


def filter_and_transform(
    items: Iterator[T],
    filter_fn: Callable[[T], bool],
    transform_fn: Callable[[T], R]
) -> list[R]:
    filtered = (item for item in items if filter_fn(item))

    if not any(filtered):
        logger.info("No items passed filter")
        return []

    return [transform_fn(item) for item in filtered]


def batch_process(items: Iterator[T], batch_size: int) -> Iterator[list[T]]:
    batch = []
    for item in items:
        batch.append(item)
        if len(batch) >= batch_size:
            yield batch
            batch = []
    if batch:
        yield batch


def get_statistics(numbers: Iterator[float]) -> dict:
    numbers_list = list(numbers)

    if not numbers_list:
        return {"count": 0, "sum": 0, "avg": 0, "min": 0, "max": 0}

    return {
        "count": len(numbers_list),
        "sum": sum(numbers_list),
        "avg": sum(numbers_list) / len(numbers_list),
        "min": min(numbers_list),
        "max": max(numbers_list)
    }


class DataPipeline:
    def __init__(self):
        self.steps: list[Callable] = []

    def add_step(self, step: Callable):
        self.steps.append(step)
        return self

    def execute(self, data: Iterable[T]) -> list:
        current = iter(data)
        for step in self.steps:
            current = step(current)
        return list(current)


def validate_all(items: Iterator[T], validator: Callable[[T], bool]) -> tuple[bool, list[T]]:
    invalid_items = [item for item in items if not validator(item)]

    all_valid = len(invalid_items) == 0

    valid_items = [item for item in items if validator(item)]

    return all_valid, valid_items

package com.app.analytics;

import java.util.*;

public class MetricsCalculator {

    public Long sumValues(List<Long> values) {
        Long sum = 0L;
        for (Long value : values) {
            sum += value;
        }
        return sum;
    }

    public Double calculateAverage(List<Integer> numbers) {
        if (numbers.isEmpty()) {
            return 0.0;
        }

        Integer sum = 0;
        for (Integer num : numbers) {
            sum += num;
        }

        return sum.doubleValue() / numbers.size();
    }

    public Integer findMax(int[] values) {
        Integer max = Integer.MIN_VALUE;
        for (int i = 0; i < values.length; i++) {
            if (values[i] > max) {
                max = values[i];
            }
        }
        return max;
    }

    public Map<String, Long> countOccurrences(List<String> items) {
        Map<String, Long> counts = new HashMap<>();
        for (String item : items) {
            Long current = counts.getOrDefault(item, 0L);
            counts.put(item, current + 1);
        }
        return counts;
    }

    public Double calculatePercentile(List<Double> values, int percentile) {
        if (values.isEmpty()) {
            return 0.0;
        }

        Collections.sort(values);
        Integer index = (int) Math.ceil(percentile / 100.0 * values.size()) - 1;
        return values.get(Math.max(0, index));
    }

    public List<Integer> filterAboveThreshold(List<Integer> values, Integer threshold) {
        List<Integer> result = new ArrayList<>();
        for (Integer value : values) {
            if (value > threshold) {
                result.add(value);
            }
        }
        return result;
    }

    public Double standardDeviation(List<Double> values) {
        Double avg = values.stream().mapToDouble(d -> d).average().orElse(0.0);
        Double sumSquares = 0.0;

        for (Double value : values) {
            Double diff = value - avg;
            sumSquares += diff * diff;
        }

        return Math.sqrt(sumSquares / values.size());
    }
}

