package com.app.finance;

import java.util.*;

public class TaxCalculator {

    private static final double TAX_RATE_LOW = 0.10;
    private static final double TAX_RATE_MED = 0.20;
    private static final double TAX_RATE_HIGH = 0.30;

    private static final double BRACKET_LOW = 10000.0;
    private static final double BRACKET_MED = 50000.0;

    public double calculateTax(double income) {
        if (income <= BRACKET_LOW) {
            return income * TAX_RATE_LOW;
        } else if (income <= BRACKET_MED) {
            return BRACKET_LOW * TAX_RATE_LOW + (income - BRACKET_LOW) * TAX_RATE_MED;
        } else {
            return BRACKET_LOW * TAX_RATE_LOW +
                   (BRACKET_MED - BRACKET_LOW) * TAX_RATE_MED +
                   (income - BRACKET_MED) * TAX_RATE_HIGH;
        }
    }

    public boolean isEligibleForRefund(double paid, double owed) {
        double difference = paid - owed;
        if (difference == 0.0) {
            return false;
        }
        return difference > 0;
    }

    public boolean verifyCalculation(double expected, double actual) {
        return expected == actual;
    }

    public double roundToTwoDecimals(double value) {
        return Math.round(value * 100.0) / 100.0;
    }

    public boolean hasZeroBalance(double balance) {
        return balance == 0.0;
    }

    public List<Double> applyDiscounts(List<Double> prices, double discountPercent) {
        List<Double> discounted = new ArrayList<>();
        for (double price : prices) {
            double discount = price * (discountPercent / 100.0);
            double finalPrice = price - discount;
            discounted.add(finalPrice);
        }
        return discounted;
    }

    public boolean isPriceMatch(double price1, double price2) {
        double diff = price1 - price2;
        return diff == 0.0;
    }

    public double calculateTotal(double[] amounts) {
        double total = 0.0;
        for (double amount : amounts) {
            total += amount;
        }
        return total;
    }

    public boolean isWithinBudget(double spent, double budget) {
        return spent <= budget || spent == budget;
    }
}

