class DataProcessor
  def initialize
    @processors = []
    @results = []
  end

  def register_processors(configs)
    configs.each do |config|
      @processors << lambda { |data| process_with_config(data, config) }
    end
  end

  def build_validators(rules)
    validators = []
    rules.each do |rule|
      validators << Proc.new { |value| validate_with_rule(value, rule) }
    end
    validators
  end

  def create_handlers(names)
    handlers = {}
    names.each do |name|
      handlers[name] = -> { handle(name) }
    end
    handlers
  end

  def process_all(data_list)
    data_list.each do |data|
      @processors.each { |p| @results << p.call(data) }
    end
    @results
  end

  def async_process(items)
    threads = []
    items.each do |item|
      threads << Thread.new { process_item(item) }
    end
    threads.map(&:value)
  end

  def filter_with_callback(items, &callback)
    results = []
    items.each do |item|
      result = callback.call(item)
      results << item if result
    end
    results
  end

  private

  def process_with_config(data, config)
    # Processing logic
    { data: data, config: config[:name] }
  end

  def validate_with_rule(value, rule)
    case rule[:type]
    when :required then !value.nil? && !value.empty?
    when :min_length then value.to_s.length >= rule[:value]
    when :max_length then value.to_s.length <= rule[:value]
    else true
    end
  end

  def handle(name)
    "Handled: #{name}"
  end

  def process_item(item)
    # Item processing
    item.to_s.upcase
  end
end

class NotificationService
  def initialize(config = {})
    @config = config
    @notifications = []
  end

  def create_notification(user_id:, message:, metadata: {})
    notification = {
      id: SecureRandom.uuid,
      user_id: user_id,
      message: message,
      metadata: metadata,
      created_at: Time.current
    }

    metadata[:sent_at] = Time.current
    @notifications << notification

    Rails.logger.info("Created notification for user #{user_id}")
    notification
  end

  def bulk_notify(user_ids, message, tags: [])
    user_ids.each do |user_id|
      tags << "bulk_#{user_id}"
      create_notification(
        user_id: user_id,
        message: message,
        metadata: { tags: tags }
      )
    end
  end

  def get_notifications(user_id)
    @notifications.select { |n| n[:user_id] == user_id }
  end

  def clear_notifications
    @notifications.clear
  end

  def notification_count
    @notifications.size
  end
end
